import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CCylkYel.js";const p=JSON.parse('{"title":"S32 User Manual","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"};function n(i,e,d,c,h,l){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="s32-user-manual" tabindex="-1">S32 User Manual <a class="header-anchor" href="#s32-user-manual" aria-label="Permalink to &quot;S32 User Manual&quot;">​</a></h1><p>Welcome to the Shik S32 User Manual.</p><p>The S32 is a 32-knob MIDI controller with a built-in MIDI processing engine, 16 LFOs, and flexible routing options. This manual explains how to set up the S32, control your MIDI gear, build MIDI racks, use modulation, and save your setups.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use <strong>Search</strong> in the header, or press <strong>Ctrl+K</strong>, to quickly find any page, device, or parameter.</p></div><h2 id="what-you-can-do-with-the-s32" tabindex="-1">What you can do with the S32 <a class="header-anchor" href="#what-you-can-do-with-the-s32" aria-label="Permalink to &quot;What you can do with the S32&quot;">​</a></h2><h3 id="control-your-gear" tabindex="-1">Control your gear <a class="header-anchor" href="#control-your-gear" aria-label="Permalink to &quot;Control your gear&quot;">​</a></h3><p>Each knob can send up to four MIDI macros. These can control MIDI CC, Program Change, SysEx, device parameters, and more.</p><h3 id="process-midi" tabindex="-1">Process MIDI <a class="header-anchor" href="#process-midi" aria-label="Permalink to &quot;Process MIDI&quot;">​</a></h3><p>Build MIDI racks using devices such as arpeggiators, scale tools, harmonizers, delays, Euclidean sequencers, filters, and other MIDI processors.</p><h3 id="add-movement" tabindex="-1">Add movement <a class="header-anchor" href="#add-movement" aria-label="Permalink to &quot;Add movement&quot;">​</a></h3><p>Use 16 LFOs to modulate device parameters, macro values, and other controls inside the system.</p><h3 id="save-your-setups" tabindex="-1">Save your setups <a class="header-anchor" href="#save-your-setups" aria-label="Permalink to &quot;Save your setups&quot;">​</a></h3><p>Save your work as <strong>projects</strong> and snapshots. Use <strong>Save Project</strong> to keep setups across power cycles; add a <strong>microSD</strong> card for extra backup (see <a href="./settings/storage-info">Storage Info</a>).</p><h3 id="route-midi-anywhere" tabindex="-1">Route MIDI anywhere <a class="header-anchor" href="#route-midi-anywhere" aria-label="Permalink to &quot;Route MIDI anywhere&quot;">​</a></h3><p>Send and receive MIDI through USB, two MIDI outputs, MIDI Thru, USB Host, and virtual ports between racks.</p><h2 id="first-steps" tabindex="-1">First steps <a class="header-anchor" href="#first-steps" aria-label="Permalink to &quot;First steps&quot;">​</a></h2><ol><li>Read <a href="./getting-started/hardware">Hardware</a> — controls and rear-panel connections.</li><li>Follow <a href="./getting-started/quick-start">Quick Start</a> — power on, open menus, build your first rack.</li><li>Learn <a href="./perform/knob-view">Perform</a> — the screen you see every time you power on.</li></ol><h2 id="main-sections" tabindex="-1">Main sections <a class="header-anchor" href="#main-sections" aria-label="Permalink to &quot;Main sections&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Page</th></tr></thead><tbody><tr><td>Physical controls</td><td><a href="./navigation/controls">Controls</a></td></tr><tr><td>Knobs &amp; macros</td><td><a href="./perform/knob-view">Perform</a></td></tr><tr><td>Knob &amp; external mapping</td><td><a href="./concepts/mapping">Mapping</a></td></tr><tr><td>MIDI effect chains</td><td><a href="./concepts/rack-chains">Rack chains</a></td></tr><tr><td>LFO modulation</td><td><a href="./concepts/modulation">Modulation</a></td></tr><tr><td>Every MIDI device</td><td><a href="./devices/">Device reference</a></td></tr><tr><td>Messages &amp; errors</td><td><a href="./getting-started/troubleshooting">Troubleshooting</a></td></tr></tbody></table>',19)])])}const m=a(s,[["render",n]]);export{p as __pageData,m as default};
